// Helpers for the fused all-reduce + RMSNorm epilogue.
template <typename T>
__quickreduce_device_inline__ float sum_squares_chunk(int32x4_t chunk);

template <>
__quickreduce_device_inline__ float sum_squares_chunk<half>(int32x4_t chunk)
{
    const half2* h2 = reinterpret_cast<const half2*>(&chunk);
    float sum = 0.0f;
#pragma unroll
    for(int j = 0; j < 4; ++j)
    {
        float2 f = __half22float2(h2[j]);
        sum += f.x * f.x + f.y * f.y;
    }
    return sum;
}

template <>
__quickreduce_device_inline__ float sum_squares_chunk<__hip_bfloat16>(int32x4_t chunk)
{
    const nv_bfloat162* bf2 = reinterpret_cast<const nv_bfloat162*>(&chunk);
    float sum = 0.0f;
#pragma unroll
    for(int j = 0; j < 4; ++j)
    {
        float2 f = __bfloat1622float2(bf2[j]);
        sum += f.x * f.x + f.y * f.y;
    }
    return sum;
}

template <typename T>
__quickreduce_device_inline__ int32x4_t apply_scale_and_weight(int32x4_t data_chunk,
                                                               int32x4_t weight_chunk,
