#!/usr/bin/env python3
import csv
import sys

def parse_csv(path):
    kernels = []
    with open(path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            if row['Kind'] != 'KERNEL_DISPATCH':
                continue
            name = row['Kernel_Name']
            start = int(row['Start_Timestamp'])
            end = int(row['End_Timestamp'])
            dur_us = (end - start) / 1000.0
            kernels.append((name, dur_us))
    return kernels

def summarize(kernels, label):
    print(f"\n{label}")
    by_name = {}
    for name, dur in kernels:
        by_name.setdefault(name, []).append(dur)
    for name, durs in sorted(by_name.items(), key=lambda x: -len(x[1])):
        if len(durs) > 3:
            avg = sum(durs) / len(durs)
            print(f"  {name[:80]:80s} count={len(durs):3d} avg={avg:.3f} ms")
            return name, avg
    return None, 0.0

fused = parse_csv('/tmp/rocprof_fused_csv/fused_csv_kernel_trace.csv')
unfused = parse_csv('/tmp/rocprof_unfused_csv/unfused_csv_kernel_trace.csv')

fused_name, fused_avg = summarize(fused, 'FUSED')

unfused_ar_name, unfused_ar_avg = None, 0.0
unfused_norm_name, unfused_norm_avg = None, 0.0
print("\nUNFUSED")
by_name = {}
for name, dur in unfused:
    by_name.setdefault(name, []).append(dur)
for name, durs in by_name.items():
    avg = sum(durs) / len(durs)
    print(f"  {name[:80]:80s} count={len(durs):3d} avg={avg:.3f} ms")
    if 'allreduce_prototype_twoshot' in name:
        unfused_ar_name, unfused_ar_avg = name, avg
    elif 'rmsnorm' in name.lower() or 'add_rmsnorm' in name.lower():
        unfused_norm_name, unfused_norm_avg = name, avg

unfused_sum = unfused_ar_avg + unfused_norm_avg
