#!/usr/bin/env python3
import csv

def parse_csv(path):
    kernels = []
    with open(path) as f:
        reader = csv.DictReader(f)
        for row in reader:
            if row['Kind'] != 'KERNEL_DISPATCH':
                continue
            name = row['Kernel_Name']
            start = int(row['Start_Timestamp'])
            end = int(row['End_Timestamp'])
            dur_us = (end - start) / 1000.0
            kernels.append((name, dur_us))
    return kernels

def summarize(kernels, label, target_substr):
    print(f"\n{label}")
    by_name = {}
    for name, dur in kernels:
        by_name.setdefault(name, []).append(dur)
    matched = []
    for name, durs in by_name.items():
        if target_substr in name:
            avg = sum(durs) / len(durs)
            matched.append((name, avg, len(durs)))
    if not matched:
        print("  No matching kernel found")
        return None, 0.0
    matched.sort(key=lambda x: -x[2])
    for name, avg, cnt in matched:
        print(f"  {name[:80]:80s} count={cnt:3d} avg={avg:.3f} ms")
    return matched[0][0], matched[0][1]

fused = parse_csv('/tmp/rocprof_fused_csv2/fused_kernel_trace.csv')
unfused = parse_csv('/tmp/rocprof_unfused_csv2/unfused_kernel_trace.csv')

fused_name, fused_avg = summarize(fused, 'FUSED', 'allreduce_rmsnorm_prototype_twoshot')
unfused_ar_name, unfused_ar_avg = summarize(unfused, 'UNFUSED AR', 'allreduce_prototype_twoshot')
unfused_norm_name, unfused_norm_avg = summarize(unfused, 'UNFUSED NORM', 'rmsnorm')

unfused_sum = unfused_ar_avg + unfused_norm_avg
print(f"\nUnfused sum (ar + norm) = {unfused_sum:.3f} ms")
print(f"Fused avg               = {fused_avg:.3f} ms")
if unfused_sum > 0:
    print(f"Improvement             = {(unfused_sum - fused_avg) / unfused_sum * 100:.2f}%")

